import type { PointsProduct, PointsProductsApiResponse } from '../models';

export function mapProductsResponse(response: PointsProductsApiResponse): PointsProduct[] {
  return response?.data?.data?.products ?? [];
}

export function extractConversionFactor(products: PointsProduct[]): number {
  for (const product of products) {
    if (product.convertionFactor && product.convertionFactor > 0) {
      return product.convertionFactor;
    }
  }
  return 0;
}

export function extractInvoiceConversionFactor(products: PointsProduct[]): number | undefined {
  const invoiceProduct = products.find(
    (product) =>
      product.name?.toLowerCase().includes('fatura') ||
      product.action?.toLowerCase().includes('fatura')
  );

  return invoiceProduct?.conversionFactor;
}

export function isSuccessResponse(response: PointsProductsApiResponse): boolean {
  const returnCode =
    response?.data?.status?.returnCode ?? response?.data?.status?.codigoRetorno ?? -1;
  return returnCode === 0;
}

